import React, { useEffect, useState } from "react";
import { getDesigners, createDesigner, updateDesigner, deleteDesigner } from "../api";
import DesignerForm from "./DesignerForm";
import "../style.css";

const DesignerList = () => {
  const [designers, setDesigners] = useState([]);
  const [editing, setEditing] = useState(null);

  const fetchData = async () => {
    const { data } = await getDesigners();
    setDesigners(data);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleAdd = async (designer) => {
    if (editing) {
      await updateDesigner(editing._id, designer);
      setEditing(null);
    } else {
      await createDesigner(designer);
    }
    fetchData();
  };

  const handleDelete = async (id) => {
    await deleteDesigner(id);
    fetchData();
  };

  return (
    <div className="page">
      <DesignerForm onSubmit={handleAdd} existingData={editing} onCancel={() => setEditing(null)} />
      <h3>Designers List</h3>
      <table>
        <thead>
          <tr>
            <th>Name</th><th>Email</th><th>Type</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {designers.map((d) => (
            <tr key={d._id}>
              <td
                className="designer-name"
                onClick={() => alert(`Name: ${d.name}\nEmail: ${d.email}\nType: ${d.type}\nPrevious: ${d.previousDesigns.join(", ")}`)}
              >
                {d.name}
              </td>
              <td>{d.email}</td>
              <td>{d.type}</td>
              <td>
                <button onClick={() => setEditing(d)}>✏️</button>
                <button onClick={() => handleDelete(d._id)}>🗑️</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DesignerList;
